BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?stakeholder ?stakeholderName WHERE {
  VALUES ?mission {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::Mission::APS%2520Mission>
  }

  # Stakeholders inferred as dependency clients related to elements owned by the APS Mission
  ?mission vocab:Element_ownedElement+ ?ownedElem .

  ?ownedDep rdf:type vocab:dependency .
  ?ownedDep vocab:Dependency_client ?stakeholder .
  FILTER EXISTS { ?ownedElem vocab:Element__relationshipOfRelatedElement ?ownedDep }

  ?stakeholder vocab:NamedElement_name ?stakeholderName .
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?dep ?depName ?client ?clientName ?supplier ?supplierName WHERE {
  VALUES ?mission {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::Mission::APS%2520Mission>
  }

  ?mission vocab:Element_ownedElement+ ?ownedElem .
  ?dep rdf:type vocab:dependency .
  FILTER EXISTS { ?ownedElem vocab:Element__relationshipOfRelatedElement ?dep }

  OPTIONAL { ?dep vocab:NamedElement_name ?depName }
  OPTIONAL { ?dep vocab:Dependency_client ?client .
             ?client vocab:NamedElement_name ?clientName . }
  OPTIONAL { ?dep vocab:Dependency_supplier ?supplier .
             ?supplier vocab:NamedElement_name ?supplierName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?actor ?actorName ?usecase ?usecaseName WHERE {
  VALUES ?mission {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::Mission::APS%2520Mission>
  }

  ?mission vocab:Element_ownedElement+ ?ownedElem .

  ?usecase rdf:type vocab:usecase .
  FILTER EXISTS { ?ownedElem vocab:Element__ownedElement+ ?usecase }

  ?usecase vocab:UseCase_include ?inc .
  OPTIONAL {
    ?inc rdf:type vocab:include .
    BIND(?inc AS ?includeRel)
  }

  # Actor is modeled as an actor classifier that includes/uses the UseCase
  ?actor rdf:type vocab:actor .
  OPTIONAL {
    ?actor vocab:NamedElement_name ?actorName .
  }
  OPTIONAL {
    ?usecase vocab:NamedElement_name ?usecaseName .
  }

  # Heuristic linkage: actor is client of a dependency related to the usecase (or included)
  FILTER EXISTS { ?actor vocab:clientDependency ?depClient . }
  FILTER EXISTS { ?depClient vocab:NamedElement_name ?actorName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?related ?relatedName ?relPred WHERE {
  VALUES ?mission {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::Mission::APS%2520Mission>
  }

  # Candidate stakeholder links via common SysML relationship patterns
  {
    ?rel rdf:type ?relType ; ?relPred ?mission .
    FILTER(?relPred IN (vocab:usage, vocab:allocate, vocab:satisfy, vocab:verify, vocab:expose)).
    BIND(?relPred AS ?relPred)
    OPTIONAL { ?rel vocab:NamedElement_name ?relatedName . }
    OPTIONAL { BIND(?rel AS ?related) }
  }

  UNION

  {
    ?mission ?incomingPred ?related .
    FILTER(?incomingPred IN (vocab:client, vocab:Dependency_client, vocab:supplier, vocab:Dependency_supplier, vocab:expose, vocab:usage, vocab:allocate, vocab:satisfy, vocab:verify)).
    OPTIONAL { ?related vocab:NamedElement_name ?relatedName . }
    BIND(?incomingPred AS ?relPred)
  }

  UNION

  {
    ?mission vocab:Element_ownedElement+ ?related .
    OPTIONAL { ?related vocab:NamedElement_name ?relatedName . }
    BIND(vocab:Element_ownedElement AS ?relPred)
  }
}
LIMIT 25

