PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?stakeholder ?stakeholderName ?stakeholderType WHERE {
  VALUES ?mission {
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::Mission::APS%2520Mission>
  }

  ?mission vocab:Element_ownedElement+ ?stakeholder .
  ?stakeholder rdf:type ?stakeholderType .

  FILTER(?stakeholderType IN (vocab:actor, vocab:interface, vocab:port, vocab:participant, vocab:class, vocab:component, vocab:block))

  OPTIONAL { ?stakeholder vocab:NamedElement_name ?stakeholderName . }
  FILTER(BOUND(?stakeholderName))
}
ORDER BY ?stakeholderName
LIMIT 25
